    52→  // method = token
    53→  static absl::node_hash_set<absl::string_view> kHttpMethodRegistry = {
    54→      "ACL",
    55→      "BASELINE-CONTROL",
    56→      "BIND",
    57→      "CHECKIN",
    58→      "CHECKOUT",
    59→      "CONNECT",
    60→      "COPY",
    61→      "DELETE",
    62→      "GET",
    63→      "HEAD",
    64→      "LABEL",
    65→      "LINK",
    66→      "LOCK",
    67→      "MERGE",
    68→      "MKACTIVITY",
    69→      "MKCALENDAR",
    70→      "MKCOL",
    71→      "MKREDIRECTREF",
    72→      "MKWORKSPACE",
    73→      "MOVE",
    74→      "OPTIONS",
    75→      "ORDERPATCH",
    76→      "PATCH",
    77→      "POST",
    78→      "PRI",
    79→      "PROPFIND",
    80→      "PROPPATCH",
    81→      "PUT",
    82→      "REBIND",
    83→      "REPORT",
    84→      "SEARCH",
    85→      "TRACE",
    86→      "UNBIND",
    87→      "UNCHECKOUT",
    88→      "UNLINK",
    89→      "UNLOCK",
    90→      "UPDATE",
    91→      "UPDATEREDIRECTREF",
    92→      "VERSION-CONTROL",
    93→      "*",
    94→  };
    95→
    96→  const auto& method = value.getStringView();
    97→  bool is_valid = true;
    98→
    99→  if (config_.restrict_http_methods()) {
   100→    is_valid = kHttpMethodRegistry.contains(method);
   101→  } else {
   102→    is_valid = !method.empty();
   103→    for (auto iter = method.begin(); iter != method.end() && is_valid; ++iter) {
   104→      is_valid &= testCharInTable(kMethodHeaderCharTable, *iter);
   105→    }
   106→  }
   107→
   108→  if (!is_valid) {
   109→    return {HeaderValueValidationResult::Action::Reject,
   110→            UhvResponseCodeDetail::get().InvalidMethod};
   111→  }
   112→
   113→  return HeaderValueValidationResult::success();
   114→}
   115→
   116→HeaderValidator::HeaderValueValidationResult
   117→HeaderValidator::validateSchemeHeader(const HeaderString& value) {
   118→  // From RFC 3986, https://datatracker.ietf.org/doc/html/rfc3986#section-3.1:
   119→  //
   120→  // scheme = ALPHA *( ALPHA / DIGIT / "+" / "-" / "." )
   121→  //
   122→  // Although schemes are case-insensitive, the canonical form is lowercase and documents that
   123→  // specify schemes must do so with lowercase letters. An implementation should accept uppercase
   124→  // letters as equivalent to lowercase in scheme names (e.g., allow "HTTP" as well as "http") for
   125→  // the sake of robustness but should only produce lowercase scheme names for consistency.
   126→  //
   127→  // The validation mode controls whether uppercase letters are permitted.
   128→  absl::string_view scheme = value.getStringView();
   129→
   130→  if (!absl::EqualsIgnoreCase(scheme, "http") && !absl::EqualsIgnoreCase(scheme, "https")) {
   131→    // TODO(#23313) - Honor config setting for mixed case.
   132→    return {HeaderValueValidationResult::Action::Reject,
   133→            UhvResponseCodeDetail::get().InvalidScheme};
   134→  }
   135→
   136→  return HeaderValueValidationResult::success();
   137→}
   138→
   139→HeaderValidator::HeaderValueValidationResult
   140→HeaderValidator::validateStatusHeader(const HeaderString& value) {
   141→  // Validate that the response :status header is a valid whole number between 100 and 999
   142→  // (inclusive). This is based on RFC 9110, although the Envoy implementation is more permissive
   143→  // and allows status codes larger than 599,
   144→  // https://www.rfc-editor.org/rfc/rfc9110.html#section-15:
   145→  //
   146→  // The status code of a response is a three-digit integer code that describes the result of the
   147→  // request and the semantics of the response, including whether the request was successful and
   148→  // what content is enclosed (if any). All valid status codes are within the range of 100 to 599,
   149→  // inclusive.
   150→
   151→  static uint32_t kMinimumResponseStatusCode = 100;
   152→  static uint32_t kMaximumResponseStatusCode = 999;
   153→  const auto& value_string_view = value.getStringView();
   154→
   155→  // Convert the status to an integer.
   156→  std::uint32_t status_value{};
   157→  auto result = fromChars(value_string_view, status_value);
   158→  if (result.ec != std::errc() ||
   159→      result.ptr != (value_string_view.data() + value_string_view.size())) {
   160→    return {HeaderValueValidationResult::Action::Reject,
   161→            UhvResponseCodeDetail::get().InvalidStatus};
   162→  }
   163→
   164→  if (status_value < kMinimumResponseStatusCode || status_value > kMaximumResponseStatusCode) {
   165→    return {HeaderValueValidationResult::Action::Reject,
   166→            UhvResponseCodeDetail::get().InvalidStatus};
   167→  }
   168→
   169→  return HeaderValueValidationResult::success();
   170→}
   171→
   172→HeaderValidator::HeaderEntryValidationResult
   173→HeaderValidator::validateGenericHeaderName(const HeaderString& name) {
   174→  // Verify that the header name is valid. This also honors the underscore in
   175→  // header configuration setting.
   176→  //
   177→  // From RFC 9110, https://www.rfc-editor.org/rfc/rfc9110.html#section-5.1:
   178→  //
   179→  // header-field   = field-name ":" OWS field-value OWS
   180→  // field-name     = token
   181→  // token          = 1*tchar
   182→  //
   183→  // tchar          = "!" / "#" / "$" / "%" / "&" / "'" / "*"
   184→  //                / "+" / "-" / "." / "^" / "_" / "`" / "|" / "~"
   185→  //                / DIGIT / ALPHA
   186→  //                ; any VCHAR, except delimiters
   187→  const auto& key_string_view = name.getStringView();
   188→  // This header name is initially invalid if the name is empty.
   189→  if (key_string_view.empty()) {
   190→    return {HeaderEntryValidationResult::Action::Reject,
   191→            UhvResponseCodeDetail::get().EmptyHeaderName};
   192→  }
   193→
   194→  const bool reject_header_names_with_underscores =
   195→      config_.headers_with_underscores_action() == HeaderValidatorConfig::REJECT_REQUEST;
   196→  bool is_valid = true;
   197→  bool reject_due_to_underscore = false;
   198→  char c = '\0';
   199→
   200→  for (auto iter = key_string_view.begin();
   201→       iter != key_string_view.end() && is_valid && !reject_due_to_underscore; ++iter) {
   202→    c = *iter;
   203→    if (c != '_') {
   204→      is_valid &= testCharInTable(::Envoy::Http::kGenericHeaderNameCharTable, c);
   205→    } else {
   206→      reject_due_to_underscore = reject_header_names_with_underscores;
   207→    }
   208→  }
   209→
   210→  if (!is_valid) {
   211→    return {HeaderEntryValidationResult::Action::Reject,
   212→            UhvResponseCodeDetail::get().InvalidNameCharacters};
   213→  }
   214→
   215→  if (reject_due_to_underscore) {
   216→    stats_.incRequestsRejectedWithUnderscoresInHeaders();
   217→    return {HeaderEntryValidationResult::Action::Reject,
   218→            UhvResponseCodeDetail::get().InvalidUnderscore};
   219→  }
   220→
   221→  return HeaderEntryValidationResult::success();
   222→}
   223→
   224→HeaderValidator::HeaderValueValidationResult
   225→HeaderValidator::validateGenericHeaderValue(const HeaderString& value) {
   226→  // Verify that the header value is valid.
   227→  //
   228→  // From RFC 9110, https://www.rfc-editor.org/rfc/rfc9110.html#section-5.5:
   229→  //
   230→  // header-field   = field-name ":" OWS field-value OWS
   231→  // field-value    = *field-content
   232→  // field-content  = field-vchar
   233→  //                  [ 1*( SP / HTAB / field-vchar ) field-vchar ]
   234→  // field-vchar    = VCHAR / obs-text
   235→  // obs-text       = %x80-FF
   236→  //
   237→  // VCHAR          =  %x21-7E
   238→  //                   ; visible (printing) characters
   239→  const auto& value_string_view = value.getStringView();
   240→  bool is_valid = true;
   241→
   242→  for (auto iter = value_string_view.begin(); iter != value_string_view.end() && is_valid; ++iter) {
   243→    is_valid &= testCharInTable(kGenericHeaderValueCharTable, *iter);
   244→  }
   245→
   246→  if (!is_valid) {
   247→    return {HeaderValueValidationResult::Action::Reject,
   248→            UhvResponseCodeDetail::get().InvalidValueCharacters};
   249→  }
   250→
   251→  return HeaderValueValidationResult::success();
   252→}
