   423→HeaderValidator::HeaderValueValidationResult
   424→HeaderValidator::validatePathHeaderCharacters(const HeaderString& value) {
   425→  return validatePathHeaderCharacterSet(value, kPathHeaderCharTable,
   426→                                        ::Envoy::Http::kUriQueryAndFragmentCharTable);
