   554→
   555→HeaderValidator::HeaderEntryValidationResult HeaderValidator::validateGenericRequestHeaderEntry(
   556→    const ::Envoy::Http::HeaderString& key, const ::Envoy::Http::HeaderString& value,
   557→    const HeaderValidatorMap& protocol_specific_header_validators) {
   558→  const auto& key_string_view = key.getStringView();
   559→  if (key_string_view.empty()) {
   560→    // reject empty header names
   561→    return {HeaderEntryValidationResult::Action::Reject,
   562→            UhvResponseCodeDetail::get().EmptyHeaderName};
   563→  }
   564→
   565→  // Protocol specific header validators use this map to check protocol specific headers. For
   566→  // example the transfer-encoding header checks are different for H/1 and H/2 or H/3.
   567→  // This map also contains validation methods for headers that have additional restrictions other
   568→  // than the generic character set (such as :method). The headers that are not part of this map,
   569→  // just need the character set validation.
   570→  auto validator_it = protocol_specific_header_validators.find(key_string_view);
   571→  if (validator_it != protocol_specific_header_validators.end()) {
   572→    const auto& validator = validator_it->second;
   573→    return validator(value);
   574→  }
   575→
   576→  if (key_string_view.at(0) != ':') {
   577→    // Validate the (non-pseudo) header name
   578→    auto name_result = validateGenericHeaderName(key);
   579→    if (!name_result) {
   580→      return name_result;
   581→    }
   582→  } else {
   583→    // header_validator_map contains every known pseudo header. If the header name starts with ":"
   584→    // and we don't have a validator registered in the map, then the header name is an unknown
   585→    // pseudo header.
   586→    return {HeaderEntryValidationResult::Action::Reject,
   587→            UhvResponseCodeDetail::get().InvalidPseudoHeader};
   588→  }
   589→
   590→  return validateGenericHeaderValue(value);
   591→}
   592→
   593→// For all (H/1, H/2 and H/3) protocols, trailers should only contain generic headers. As such a
   594→// common validation method can be used.
   595→// More in depth explanation for using common function:
   596→// For H/2 (and so H/3), per
   597→// https://www.rfc-editor.org/rfc/rfc9113#section-8.1 trailers MUST NOT contain pseudo header
   598→// fields.
   599→// For H/1 the codec will never produce H/2 pseudo headers and per
   600→// https://www.rfc-editor.org/rfc/rfc9110#section-6.5 there are no other prohibitions.
   601→// As a result this common function can cover trailer validation for all protocols.
   602→::Envoy::Http::HeaderValidator::ValidationResult
   603→HeaderValidator::validateTrailers(const ::Envoy::Http::HeaderMap& trailers) {
   604→  std::string reject_details;
   605→  trailers.iterate([this, &reject_details](const ::Envoy::Http::HeaderEntry& header_entry)
   606→                       -> ::Envoy::Http::HeaderMap::Iterate {
   607→    const auto& header_name = header_entry.key();
   608→    const auto& header_value = header_entry.value();
   609→
   610→    auto entry_name_result = validateGenericHeaderName(header_name);
   611→    if (!entry_name_result.ok()) {
   612→      reject_details = static_cast<std::string>(entry_name_result.details());
   613→    } else {
   614→      auto entry_value_result = validateGenericHeaderValue(header_value);
   615→      if (!entry_value_result) {
   616→        reject_details = static_cast<std::string>(entry_value_result.details());
   617→      }
   618→    }
   619→
   620→    return reject_details.empty() ? ::Envoy::Http::HeaderMap::Iterate::Continue
   621→                                  : ::Envoy::Http::HeaderMap::Iterate::Break;
   622→  });
   623→
   624→  if (!reject_details.empty()) {
   625→    return {::Envoy::Http::HeaderValidator::ValidationResult::Action::Reject, reject_details};
   626→  }
   627→
   628→  return ::Envoy::Http::HeaderValidator::ValidationResult::success();
   629→}
   630→
   631→void HeaderValidator::sanitizeHeadersWithUnderscores(::Envoy::Http::HeaderMap& header_map) {
   632→  const auto& underscore_action = config_.headers_with_underscores_action();
   633→  if (underscore_action == HeaderValidatorConfig::ALLOW) {
   634→    return;
   635→  }
   636→
   637→  std::vector<absl::string_view> drop_headers;
   638→  header_map.iterate([&drop_headers](const ::Envoy::Http::HeaderEntry& header_entry)
   639→                         -> ::Envoy::Http::HeaderMap::Iterate {
   640→    const absl::string_view header_name = header_entry.key().getStringView();
   641→    if (absl::StrContains(header_name, '_')) {
   642→      drop_headers.push_back(header_name);
   643→    }
   644→
   645→    return ::Envoy::Http::HeaderMap::Iterate::Continue;
   646→  });
   647→
   648→  ASSERT(drop_headers.empty() || underscore_action == HeaderValidatorConfig::DROP_HEADER);
   649→  for (auto& name : drop_headers) {
   650→    stats_.incDroppedHeadersWithUnderscores();
   651→    header_map.remove(::Envoy::Http::LowerCaseString(name));
   652→  }
   653→}
   654→
   655→void HeaderValidator::sanitizePathWithFragment(::Envoy::Http::RequestHeaderMap& header_map) {
   656→  auto fragment_pos = header_map.getPathValue().find('#');
   657→  if (fragment_pos != absl::string_view::npos) {
   658→    ASSERT(config_.strip_fragment_from_path());
   659→    // Check runtime override and throw away fragment from URI path
   660→    header_map.setPath(header_map.getPathValue().substr(0, fragment_pos));
   661→  }
   662→}
   663→
   664→PathNormalizer::PathNormalizationResult
   665→HeaderValidator::sanitizeEncodedSlashes(::Envoy::Http::RequestHeaderMap& header_map) {
   666→  if (!header_map.Path()) {
   667→    return PathNormalizer::PathNormalizationResult::success();
   668→  }
   669→  const auto escaped_slashes_action =
   670→      config_.uri_path_normalization_options().path_with_escaped_slashes_action();
   671→
   672→  if (escaped_slashes_action ==
   673→      HeaderValidatorConfig::UriPathNormalizationOptions::KEEP_UNCHANGED) {
   674→    return PathNormalizer::PathNormalizationResult::success();
   675→  }
   676→  // When path normalization is enabled decoding of slashes is done as part of the normalization
   677→  // function for performance.
   678→  auto escaped_slashes_result = PathUtil::unescapeSlashes(header_map);
   679→  if (escaped_slashes_result != PathUtil::UnescapeSlashesResult::FoundAndUnescaped) {
   680→    return PathNormalizer::PathNormalizationResult::success();
   681→  }
   682→  if (escaped_slashes_action ==
   683→      HeaderValidatorConfig::UriPathNormalizationOptions::REJECT_REQUEST) {
   684→    return {PathNormalizer::PathNormalizationResult::Action::Reject,
   685→            UhvResponseCodeDetail::get().EscapedSlashesInPath};
   686→  } else if (escaped_slashes_action ==
   687→             HeaderValidatorConfig::UriPathNormalizationOptions::UNESCAPE_AND_REDIRECT) {
   688→    return {PathNormalizer::PathNormalizationResult::Action::Redirect,
   689→            ::Envoy::Http::PathNormalizerResponseCodeDetail::get().RedirectNormalized};
   690→  } else {
   691→    ASSERT(escaped_slashes_action ==
   692→           HeaderValidatorConfig::UriPathNormalizationOptions::UNESCAPE_AND_FORWARD);
   693→  }
   694→  return PathNormalizer::PathNormalizationResult::success();
   695→}
   696→
   697→PathNormalizer::PathNormalizationResult
   698→HeaderValidator::transformUrlPath(::Envoy::Http::RequestHeaderMap& header_map) {
   699→  if (!config_.uri_path_normalization_options().skip_path_normalization()) {
   700→    auto path_result = path_normalizer_.normalizePathUri(header_map);
   701→    if (!path_result.ok()) {
   702→      return path_result;
   703→    }
   704→    auto percent_00_result = checkForPercent00InUrlPath(header_map);
   705→    if (!percent_00_result.ok()) {
   706→      return {PathNormalizer::PathNormalizationResult::Action::Reject, percent_00_result.details()};
   707→    }
   708→    if (config_overrides_.allow_non_compliant_characters_in_path_) {
   709→      encodeAdditionalCharactersInPath(header_map);
   710→    }
   711→  } else {
   712→    // Path normalization includes sanitization of encoded slashes for performance reasons.
   713→    // If normalization is disabled, sanitize encoded slashes here
   714→    auto result = sanitizeEncodedSlashes(header_map);
   715→    if (!result.ok()) {
   716→      return result;
   717→    }
   718→  }
   719→  return PathNormalizer::PathNormalizationResult::success();
   720→}
   721→
   722→HeaderValidator::HeaderValueValidationResult
   723→HeaderValidator::checkForPercent00InUrlPath(const ::Envoy::Http::RequestHeaderMap& header_map) {
   724→  if (!header_map.Path() || !config_overrides_.reject_percent_00_) {
   725→    return HeaderValueValidationResult::success();
   726→  }
   727→  if (absl::StrContains(header_map.getPathValue(), "%00")) {
   728→    return {HeaderValueValidationResult::Action::Reject,
   729→            UhvResponseCodeDetail::get().Percent00InPath};
   730→  }
   731→
   732→  return HeaderValueValidationResult::success();
   733→}
