   193→
   194→  const bool reject_header_names_with_underscores =
   195→      config_.headers_with_underscores_action() == HeaderValidatorConfig::REJECT_REQUEST;
   196→  bool is_valid = true;
   197→  bool reject_due_to_underscore = false;
   198→  char c = '\0';
   199→
   200→  for (auto iter = key_string_view.begin();
   201→       iter != key_string_view.end() && is_valid && !reject_due_to_underscore; ++iter) {
   202→    c = *iter;
   203→    if (c != '_') {
   204→      is_valid &= testCharInTable(::Envoy::Http::kGenericHeaderNameCharTable, c);
   205→    } else {
   206→      reject_due_to_underscore = reject_header_names_with_underscores;
   207→    }
   208→  }
   209→
   210→  if (!is_valid) {
   211→    return {HeaderEntryValidationResult::Action::Reject,
   212→            UhvResponseCodeDetail::get().InvalidNameCharacters};
   213→  }
   214→
   215→  if (reject_due_to_underscore) {
   216→    stats_.incRequestsRejectedWithUnderscoresInHeaders();
   217→    return {HeaderEntryValidationResult::Action::Reject,
   218→            UhvResponseCodeDetail::get().InvalidUnderscore};
   219→  }
   220→
   221→  return HeaderEntryValidationResult::success();
   222→}
   223→
   224→HeaderValidator::HeaderValueValidationResult
   225→HeaderValidator::validateGenericHeaderValue(const HeaderString& value) {
   226→  // Verify that the header value is valid.
   227→  //
   228→  // From RFC 9110, https://www.rfc-editor.org/rfc/rfc9110.html#section-5.5:
   229→  //
   230→  // header-field   = field-name ":" OWS field-value OWS
   231→  // field-value    = *field-content
   232→  // field-content  = field-vchar
   233→  //                  [ 1*( SP / HTAB / field-vchar ) field-vchar ]
   234→  // field-vchar    = VCHAR / obs-text
   235→  // obs-text       = %x80-FF
   236→  //
   237→  // VCHAR          =  %x21-7E
   238→  //                   ; visible (printing) characters
   239→  const auto& value_string_view = value.getStringView();
   240→  bool is_valid = true;
   241→
   242→  for (auto iter = value_string_view.begin(); iter != value_string_view.end() && is_valid; ++iter) {
   243→    is_valid &= testCharInTable(kGenericHeaderValueCharTable, *iter);
   244→  }
   245→
   246→  if (!is_valid) {
   247→    return {HeaderValueValidationResult::Action::Reject,
   248→            UhvResponseCodeDetail::get().InvalidValueCharacters};
   249→  }
   250→
   251→  return HeaderValueValidationResult::success();
   252→}
   253→
   254→HeaderValidator::HeaderValueValidationResult
   255→HeaderValidator::validateContentLengthHeader(const HeaderString& value) {
   256→  // From RFC 9110, https://www.rfc-editor.org/rfc/rfc9110.html#section-8.6:
   257→  //
   258→  // Content-Length = 1*DIGIT
   259→  // TODO(#23315) - Validate multiple Content-Length values
   260→  const auto value_string_view = value.getStringView();
   261→
   262→  if (value_string_view.empty()) {
   263→    return {HeaderValueValidationResult::Action::Reject,
   264→            UhvResponseCodeDetail::get().InvalidContentLength};
   265→  }
   266→
   267→  std::uint64_t int_value{};
   268→  auto result = fromChars(value_string_view, int_value);
   269→  if (result.ec != std::errc() ||
   270→      result.ptr != (value_string_view.data() + value_string_view.size())) {
   271→    return {HeaderValueValidationResult::Action::Reject,
   272→            UhvResponseCodeDetail::get().InvalidContentLength};
   273→  }
   274→
   275→  return HeaderValueValidationResult::success();
   276→}
   277→
   278→HeaderValidator::HeaderValueValidationResult
   279→HeaderValidator::validateHostHeader(const HeaderString& value) {
   280→  // From RFC 9110, https://www.rfc-editor.org/rfc/rfc9110.html#section-7.2,
   281→  // and RFC 3986, https://datatracker.ietf.org/doc/html/rfc3986#section-3.2.2:
   282→  //
   283→  // Host       = uri-host [ ":" port ]
   284→  // uri-host   = IP-literal / IPv4address / reg-name
   285→  const auto host = value.getStringView();
   286→  if (host.empty()) {
   287→    return {HeaderValueValidationResult::Action::Reject, UhvResponseCodeDetail::get().InvalidHost};
   288→  }
   289→
   290→  // Check if the host/:authority contains the deprecated userinfo component. This is based on RFC
   291→  // 9110, https://www.rfc-editor.org/rfc/rfc9110.html#section-4.2.4:
   292→  //
   293→  // Before making use of an "http" or "https" URI reference received from an untrusted source, a
   294→  // recipient SHOULD parse for userinfo and treat its presence as an error; it is likely being
   295→  // used to obscure the authority for the sake of phishing attacks.
   296→  auto user_info_delimiter = host.find('@');
   297→  if (user_info_delimiter != absl::string_view::npos) {
   298→    // :authority cannot contain user info, reject the header
   299→    return {HeaderValueValidationResult::Action::Reject,
   300→            UhvResponseCodeDetail::get().InvalidHostDeprecatedUserInfo};
   301→  }
   302→
   303→  // Determine if the host is in IPv4, reg-name, or IPv6 form.
   304→  auto result = host.at(0) == '[' ? validateHostHeaderIPv6(host) : validateHostHeaderRegName(host);
   305→  if (!result.ok()) {
   306→    return {HeaderValueValidationResult::Action::Reject, result.details()};
   307→  }
   308→
   309→  const auto port_string = result.portAndDelimiter();
   310→  if (!port_string.empty()) {
   311→    // Validate the port, which will be in the form of ":<uint16_t>"
   312→    bool is_valid = true;
   313→    if (port_string.at(0) != ':') {
   314→      // The port must begin with ":"
   315→      is_valid = false;
   316→    } else {
   317→      // parse the port number
   318→      std::uint16_t port_int{};
   319→      auto result = fromChars(port_string.substr(1), port_int);
   320→      if (result.ec != std::errc() || result.ptr != (port_string.data() + port_string.size()) ||
   321→          port_int == 0) {
   322→        is_valid = false;
   323→      }
   324→    }
   325→
   326→    if (!is_valid) {
   327→      return {HeaderValueValidationResult::Action::Reject,
   328→              UhvResponseCodeDetail::get().InvalidHost};
   329→    }
   330→  }
   331→
   332→  return HeaderValueValidationResult::success();
   333→}
   334→
   335→HeaderValidator::HostHeaderValidationResult
   336→HeaderValidator::validateHostHeaderIPv6(absl::string_view host) {
   337→  // Validate an IPv6 address host header value. This is a simplified check based on RFC 3986,
   338→  // https://www.rfc-editor.org/rfc/rfc3986.html#section-3.2.2, that only validates the characters,
   339→  // not the syntax of the address.
   340→
   341→  // Validate that the address is enclosed between "[" and "]".
   342→  std::size_t closing_bracket = host.rfind(']');
   343→  if (host.empty() || host.at(0) != '[' || closing_bracket == absl::string_view::npos) {
   344→    return HostHeaderValidationResult::reject(UhvResponseCodeDetail::get().InvalidHost);
   345→  }
   346→
   347→  // Get the address substring between the brackets.
   348→  const auto address = host.substr(1, closing_bracket - 1);
   349→  // Get the trailing port substring
   350→  const auto port_string = host.substr(closing_bracket + 1);
   351→  // Validate the IPv6 address characters
   352→  if (address.empty()) {
   353→    return HostHeaderValidationResult::reject(UhvResponseCodeDetail::get().InvalidHost);
   354→  }
   355→  if (address == "::") {
   356→    return HostHeaderValidationResult::success(address, port_string);
   357→  }
   358→  // Split address by (:) and validate:
   359→  // 1. there are no more than 8 parts
   360→  // 2. each part has only hex digit and is 16-bit
   361→  // 3. only one double colon is allowed
   362→  absl::InlinedVector<absl::string_view, 8> address_components = absl::StrSplit(address, ':');
   363→  if (address_components.size() > 8) {
   364→    return HostHeaderValidationResult::reject(UhvResponseCodeDetail::get().InvalidHost);
   365→  }
   366→  uint32_t empty_string_count = 0;
   367→  for (absl::string_view cur_component : address_components) {
   368→    // each part must be 16 bits
   369→    if (cur_component.size() > 4) {
   370→      return HostHeaderValidationResult::reject(UhvResponseCodeDetail::get().InvalidHost);
   371→    }
   372→    if (cur_component.empty()) {
   373→      empty_string_count++;
   374→      continue;
   375→    }
   376→    // Validate each char is hex digit
   377→    for (char c : cur_component) {
   378→      if (!testCharInTable(kHostIPv6AddressCharTable, c)) {
   379→        return HostHeaderValidationResult::reject(UhvResponseCodeDetail::get().InvalidHost);
   380→      }
   381→    }
   382→  }
   383→  // The address should never have more than 2 empty parts, except "::"
   384→  if (empty_string_count >= 3) {
   385→    return HostHeaderValidationResult::reject(UhvResponseCodeDetail::get().InvalidHost);
   386→  }
   387→
   388→  // Double colon is allowed at the beginning or end
   389→  // Otherwise the address shouldn't have two empty parts
   390→  if (empty_string_count == 2 &&
   391→      !(absl::StartsWith(address, "::") || absl::EndsWith(address, "::"))) {
   392→    return HostHeaderValidationResult::reject(UhvResponseCodeDetail::get().InvalidHost);
   393→  }
   394→
   395→  return HostHeaderValidationResult::success(address, port_string);
   396→}
   397→
   398→HeaderValidator::HostHeaderValidationResult
   399→HeaderValidator::validateHostHeaderRegName(absl::string_view host) {
   400→  // Validate a reg-name address host header value. This is a simplified check based on RFC 3986,
   401→  // https://www.rfc-editor.org/rfc/rfc3986.html#section-3.2.2, that only validates the characters,
   402→  // not the syntax of the address.
   403→
   404→  // Identify the port trailer
   405→  auto port_delimiter = host.find(':');
   406→  const auto address = host.substr(0, port_delimiter);
   407→  bool is_valid = !address.empty();
   408→
   409→  // Validate the reg-name characters
   410→  for (auto iter = address.begin(); iter != address.end() && is_valid; ++iter) {
   411→    is_valid &= testCharInTable(kHostRegNameCharTable, *iter);
   412→  }
   413→
   414→  if (!is_valid) {
   415→    return HostHeaderValidationResult::reject(UhvResponseCodeDetail::get().InvalidHost);
   416→  }
   417→
   418→  const auto port_string =
   419→      port_delimiter != absl::string_view::npos ? host.substr(port_delimiter) : absl::string_view();
   420→  return HostHeaderValidationResult::success(address, port_string);
   421→}
