   428→
   429→HeaderValidator::HeaderValueValidationResult HeaderValidator::validatePathHeaderCharacterSet(
   430→    const HeaderString& value, const std::array<uint32_t, 8>& allowed_path_chracters,
   431→    const std::array<uint32_t, 8>& allowed_query_fragment_characters) {
   432→  static const HeaderValueValidationResult bad_path_result{
   433→      HeaderValueValidationResult::Action::Reject, UhvResponseCodeDetail::get().InvalidUrl};
   434→  const auto& path = value.getStringView();
   435→  if (path.empty()) {
   436→    return bad_path_result;
   437→  }
   438→
   439→  auto iter = path.begin();
   440→  auto end = path.end();
   441→
   442→  // Validate the path component of the URI
   443→  for (; iter != end; ++iter) {
   444→    if (*iter == '?' || *iter == '#') {
   445→      // This is the start of the query or fragment portion of the path which uses a different
   446→      // character table.
   447→      break;
   448→    }
   449→
   450→    if (!testCharInTable(allowed_path_chracters, *iter)) {
   451→      return bad_path_result;
   452→    }
   453→  }
   454→
   455→  if (iter != end && *iter == '?') {
   456→    // Validate the query component of the URI
   457→    ++iter;
   458→    for (; iter != end; ++iter) {
   459→      if (*iter == '#') {
   460→        break;
   461→      }
   462→
   463→      if (!testCharInTable(allowed_query_fragment_characters, *iter)) {
   464→        return bad_path_result;
   465→      }
   466→    }
   467→  }
   468→
   469→  if (iter != end) {
   470→    ASSERT(*iter == '#');
   471→    if (!config_.strip_fragment_from_path()) {
   472→      return {HeaderValueValidationResult::Action::Reject,
   473→              UhvResponseCodeDetail::get().FragmentInUrlPath};
   474→    }
   475→    // Validate the fragment component of the URI
   476→    ++iter;
   477→    for (; iter != end; ++iter) {
   478→      if (!testCharInTable(allowed_query_fragment_characters, *iter)) {
   479→        return bad_path_result;
   480→      }
   481→    }
   482→  }
   483→
   484→  return HeaderValueValidationResult::success();
   485→}
   486→
   487→void HeaderValidator::encodeAdditionalCharactersInPath(
   488→    // TODO(#28780): reuse Utility::PercentEncoding class for this code.
   489→
   490→    ::Envoy::Http::RequestHeaderMap& header_map) {
   491→  // " < > ^ ` { } | TAB space extended-ASCII
   492→  static constexpr std::array<uint32_t, 8> kCharactersToEncode = {
   493→      // control characters
   494→      0b00000000010000000000000000000000,
   495→      // !"#$%&'()*+,-./0123456789:;<=>?
   496→      0b10100000000000000000000000001010,
   497→      //@ABCDEFGHIJKLMNOPQRSTUVWXYZ[\]^_
   498→      0b00000000000000000000000000000010,
   499→      //`abcdefghijklmnopqrstuvwxyz{|}~
   500→      0b10000000000000000000000000011100,
   501→      // extended ascii
   502→      0b11111111111111111111111111111111,
   503→      0b11111111111111111111111111111111,
   504→      0b11111111111111111111111111111111,
   505→      0b11111111111111111111111111111111,
   506→  };
   507→
   508→  absl::string_view path = header_map.getPathValue();
   509→  // Check if URL path contains any characters in the kCharactersToEncode set
   510→  auto char_to_encode = path.begin();
   511→  for (; char_to_encode != path.end() && !testCharInTable(kCharactersToEncode, *char_to_encode);
   512→       ++char_to_encode) {
   513→    // Return early if we got to query or fragment without finding any characters that has to be
   514→    // encoded.
   515→    if (*char_to_encode == '?' || *char_to_encode == '#') {
   516→      return;
   517→    }
   518→  }
   519→  if (char_to_encode == path.end()) {
   520→    return;
   521→  }
   522→  std::string encoded_path(path.begin(), char_to_encode);
   523→  encoded_path.reserve(path.size());
   524→
   525→  for (; char_to_encode != path.end(); ++char_to_encode) {
   526→    if (*char_to_encode == '?' || *char_to_encode == '#') {
   527→      break;
   528→    }
   529→    if (testCharInTable(kCharactersToEncode, *char_to_encode)) {
   530→      absl::StrAppend(&encoded_path,
   531→                      fmt::format("%{:02X}", static_cast<const unsigned char&>(*char_to_encode)));
   532→    } else {
   533→      encoded_path.push_back(*char_to_encode);
   534→    }
   535→  }
   536→  // Append query and fragment if present
   537→  encoded_path.append(char_to_encode, path.end());
   538→  // Encoding changes the length of the path
   539→  if (encoded_path.size() > path.size()) {
   540→    header_map.setPath(encoded_path);
   541→  }
   542→}
