   438→
   439→  auto iter = path.begin();
   440→  auto end = path.end();
   441→
   442→  // Validate the path component of the URI
   443→  for (; iter != end; ++iter) {
   444→    if (*iter == '?' || *iter == '#') {
   445→      // This is the start of the query or fragment portion of the path which uses a different
   446→      // character table.
   447→      break;
   448→    }
   449→
   450→    if (!testCharInTable(allowed_path_chracters, *iter)) {
   451→      return bad_path_result;
   452→    }
   453→  }
   454→
   455→  if (iter != end && *iter == '?') {
   456→    // Validate the query component of the URI
   457→    ++iter;
   458→    for (; iter != end; ++iter) {
   459→      if (*iter == '#') {
   460→        break;
   461→      }
   462→
   463→      if (!testCharInTable(allowed_query_fragment_characters, *iter)) {
   464→        return bad_path_result;
   465→      }
   466→    }
   467→  }
   468→
   469→  if (iter != end) {
   470→    ASSERT(*iter == '#');
   471→    if (!config_.strip_fragment_from_path()) {
   472→      return {HeaderValueValidationResult::Action::Reject,
   473→              UhvResponseCodeDetail::get().FragmentInUrlPath};
   474→    }
   475→    // Validate the fragment component of the URI
   476→    ++iter;
   477→    for (; iter != end; ++iter) {
   478→      if (!testCharInTable(allowed_query_fragment_characters, *iter)) {
   479→        return bad_path_result;
   480→      }
   481→    }
   482→  }
   483→
   484→  return HeaderValueValidationResult::success();
   485→}
