   544→bool HeaderValidator::hasChunkedTransferEncoding(const HeaderString& value) {
   545→  const auto encoding = value.getStringView();
   546→  for (const auto token : StringUtil::splitToken(encoding, ",", true, true)) {
   547→    if (absl::EqualsIgnoreCase(token, header_values_.TransferEncodingValues.Chunked)) {
   548→      return true;
   549→    }
   550→  }
   551→
   552→  return false;
