    34→absl::string_view getScheme(absl::string_view forwarded_proto, bool is_ssl) {
    35→  if (Utility::schemeIsValid(forwarded_proto)) {
    36→    return forwarded_proto;
    37→  }
    38→  return is_ssl ? Headers::get().SchemeValues.Https : Headers::get().SchemeValues.Http;
    39→}
    40→
    41→// Determines the scheme (http/https) based on PROXY protocol destination port if configured,
    42→// otherwise falls back to connection's TLS status.
    43→absl::string_view getSchemeFromProxyProtocolOrConnection(const Network::Connection& connection,
    44→                                                         const ConnectionManagerConfig& config) {
    45→  const auto& https_ports = config.httpsDestinationPorts();
    46→  const auto& http_ports = config.httpDestinationPorts();
    47→
    48→  // If the feature is configured and the local address was restored from PROXY protocol,
    49→  // try to infer the scheme from the destination port.
    50→  if ((!https_ports.empty() || !http_ports.empty()) &&
    51→      connection.connectionInfoProvider().localAddressRestored()) {
    52→    const Envoy::Network::Address::Ip* ip =
    53→        connection.connectionInfoProvider().localAddress()->ip();
    54→    if (ip != nullptr) {
    55→      uint32_t port = ip->port();
    56→      if (https_ports.contains(port)) {
    57→        return Headers::get().SchemeValues.Https;
    58→      }
    59→      if (http_ports.contains(port)) {
    60→        return Headers::get().SchemeValues.Http;
    61→      }
    62→    }
    63→  }
    64→
    65→  // Fall back to connection's TLS status.
    66→  return connection.ssl() ? Headers::get().SchemeValues.Https : Headers::get().SchemeValues.Http;
    67→}
