    70→std::string ConnectionManagerUtility::determineNextProtocol(Network::Connection& connection,
    71→                                                            const Buffer::Instance& data) {
    72→  std::string next_protocol = connection.nextProtocol();
    73→  if (!next_protocol.empty()) {
    74→    return next_protocol;
    75→  }
    76→
    77→  // See if the data we have so far shows the HTTP/2 prefix. We ignore the case where someone sends
    78→  // us the first few bytes of the HTTP/2 prefix since in all public cases we use SSL/ALPN. For
    79→  // internal cases this should practically never happen.
    80→  if (data.startsWith(Http2::CLIENT_MAGIC_PREFIX)) {
    81→    return Utility::AlpnNames::get().Http2;
    82→  }
    83→
    84→  return "";
    85→}
